import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.VxKNwi4m.js";const c=JSON.parse('{"title":"부지 정보 관리","description":"","frontmatter":{},"headers":[],"relativePath":"project/site-manage.md","filePath":"project/site-manage.md","lastUpdated":1783235691000}'),n={name:"project/site-manage.md"};function r(i,t,s,g,x,o){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="부지-정보-관리" tabindex="-1">부지 정보 관리 <a class="header-anchor" href="#부지-정보-관리" aria-label="Permalink to &quot;부지 정보 관리&quot;">​</a></h1><p>프로젝트 사업 부지의 필지별 정보, 소유자 정보 및 매입 계약 현황을 통합적으로 관리합니다.</p><h2 id="지번-목록-관리" tabindex="-1">지번 목록 관리 <a class="header-anchor" href="#지번-목록-관리" aria-label="Permalink to &quot;지번 목록 관리&quot;">​</a></h2><p>사업 부지를 구성하는 개별 필지(지번)의 물리적 정보와 권리 관계를 등록합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 부지 정보 관리 &gt; 지번 목록 관리</code></li><li><strong>엑셀 다운로드</strong>: 등록된 지번 목록을 엑셀 파일로 추출할 수 있습니다. (권리제한사항 포함 여부 선택 가능)</li></ul><h4 id="주요-입력-항목" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">행정동 / 지번</td><td style="text-align:center;">필수</td><td style="text-align:left;">필지의 행정 구역 및 세부 지번</td></tr><tr><td style="text-align:left;">지목</td><td style="text-align:center;">필수</td><td style="text-align:left;">대지, 전, 답, 임야 등 토지의 용도</td></tr><tr><td style="text-align:left;">공부상 면적</td><td style="text-align:center;">필수</td><td style="text-align:left;">대장상 기재된 토지 면적 (제곱미터)</td></tr><tr><td style="text-align:left;">환지 면적</td><td style="text-align:center;"></td><td style="text-align:left;">환지 방식 사업인 경우 실제 권리 면적 (제곱미터)</td></tr><tr><td style="text-align:left;">권리 제한 사항</td><td style="text-align:center;"></td><td style="text-align:left;">갑구(소유권 관련), 을구(저당권 등) 제한 사항 기록</td></tr><tr><td style="text-align:left;">등기부 등본</td><td style="text-align:center;"></td><td style="text-align:left;">해당 필지의 등기부 등본 파일 첨부</td></tr></tbody></table><h2 id="소유자-별-관리" tabindex="-1">소유자 별 관리 <a class="header-anchor" href="#소유자-별-관리" aria-label="Permalink to &quot;소유자 별 관리&quot;">​</a></h2><p>부지 소유자의 인적 사항과 소유 지분, 토지 사용 동의 여부 등을 관리합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 부지 정보 관리 &gt; 소유자 별 관리</code></li><li><strong>엑셀 다운로드</strong>: 소유자별 지분 현황 및 연락처 목록을 엑셀 파일로 다운로드할 수 있습니다.</li></ul><h4 id="주요-입력-항목-1" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-1" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">소유구분</td><td style="text-align:center;">필수</td><td style="text-align:left;">개인, 법인, 국공유지 중 선택</td></tr><tr><td style="text-align:left;">소유자 / 생년월일</td><td style="text-align:center;">필수</td><td style="text-align:left;">소유자 성명(또는 법인명) 및 식별 정보</td></tr><tr><td style="text-align:left;">연락처 / 주소</td><td style="text-align:center;"></td><td style="text-align:left;">주/보조 연락처 및 우편번호 기반 주소 입력</td></tr><tr><td style="text-align:left;">소유부지</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 소유자가 지분을 가진 필지 선택 (다중 선택 가능)</td></tr><tr><td style="text-align:left;">소유지분 / 면적</td><td style="text-align:center;">필수</td><td style="text-align:left;">필지별 소유 지분율(%) 및 실제 소유 면적</td></tr><tr><td style="text-align:left;">사용동의</td><td style="text-align:center;"></td><td style="text-align:left;">토지 사용 승낙서 징구 여부 설정</td></tr></tbody></table><h2 id="매입-계약-관리" tabindex="-1">매입 계약 관리 <a class="header-anchor" href="#매입-계약-관리" aria-label="Permalink to &quot;매입 계약 관리&quot;">​</a></h2><p>소유자별 부지 매매 계약 조건과 대금 지급 현황을 관리합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 부지 정보 관리 &gt; 매입 계약 관리</code></li><li><strong>엑셀 다운로드</strong>: 부지 매입 계약 현황 및 대금 지급 데이터를 엑셀 파일로 추출하여 보고서 등에 활용할 수 있습니다.</li></ul><h4 id="주요-입력-항목-2" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-2" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">소유자</td><td style="text-align:center;">필수</td><td style="text-align:left;">매입 대상 소유자 선택</td></tr><tr><td style="text-align:left;">총 매매가격</td><td style="text-align:center;">필수</td><td style="text-align:left;">계약서상의 총 매도/매수 금액</td></tr><tr><td style="text-align:left;">총 계약면적</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 계약으로 확보되는 토지 면적 (제곱미터)</td></tr><tr><td style="text-align:left;">계약 체결일</td><td style="text-align:center;">필수</td><td style="text-align:left;">매매 계약서상의 계약일</td></tr><tr><td style="text-align:left;">대금 지급 정보</td><td style="text-align:center;">필수</td><td style="text-align:left;">계약금(1, 2차), 중도금, 잔금별 금액/기한/지급 여부 관리</td></tr><tr><td style="text-align:left;">입금 계좌</td><td style="text-align:center;">필수</td><td style="text-align:left;">대금 지급을 위한 은행, 계좌번호, 예금주 정보</td></tr><tr><td style="text-align:left;">소유권 확보</td><td style="text-align:center;"></td><td style="text-align:left;">소유권 이전 등기 완료 여부 설정</td></tr><tr><td style="text-align:left;">계약서 파일</td><td style="text-align:center;"></td><td style="text-align:left;">날인된 매매 계약서 스캔본 등 첨부</td></tr></tbody></table><blockquote><p><strong>참고</strong>: 부지 정보 관리는 [지번 등록] -&gt; [소유자 등록 및 지분 연결] -&gt; [매입 계약 체결] 순서로 진행하는 것이 효율적입니다. 등록된 전체 면적 현황은 각 화면 상단의 요약 정보를 통해 실시간으로 확인할 수 있습니다.</p></blockquote>',18)])])}const f=e(n,[["render",r]]);export{c as __pageData,f as default};
